// Auto-detect column structure
// Look for common column names: SKU, Name, Images, Videos, Description

const items = $input.all();

if (items.length === 0) {
  return [];
}

// Get the first row to detect column names
const firstRow = items[0].json;
const columnNames = Object.keys(firstRow);

// Map common variations to standard names
const columnMap = {
  sku: ['sku', 'item', 'item_number', 'product_id', 'product_code', 'code'],
  name: ['name', 'product_name', 'title', 'product_title', 'description'],
  images: ['images', 'image', 'image_urls', 'image_url', 'photos', 'pictures'],
  videos: ['videos', 'video', 'video_urls', 'video_url'],
  description: ['description', 'marketing_copy', 'copy', 'details', 'product_description'],
  price: ['price', 'cost', 'msrp', 'retail_price']
};

// Detect which columns map to which fields
const detectedColumns = {};

for (const [standardName, variations] of Object.entries(columnMap)) {
  for (const colName of columnNames) {
    const normalizedCol = colName.toLowerCase().trim();
    if (variations.includes(normalizedCol)) {
      detectedColumns[standardName] = colName;
      break;
    }
  }
}

// Store detected columns for next node
return [{
  json: {
    detected_columns: detectedColumns,
    total_rows: items.length,
    column_names: columnNames,
    vendor_id: $('Start').first().json.vendor_id
  }
}];

// Parse sheet data using detected columns
// Handle comma-separated URLs

const detectedColumns = $('Auto-Detect Columns').first().json.detected_columns;
const vendorId = $('Auto-Detect Columns').first().json.vendor_id;
const items = $input.all();
const results = [];

for (const item of items) {
  const row = item.json;

  // Extract SKU (required)
  const skuCol = detectedColumns.sku;
  if (!skuCol || !row[skuCol]) {
    continue; // Skip rows without SKU
  }

  const sku = String(row[skuCol]).trim().toUpperCase();

  // Extract name
  const nameCol = detectedColumns.name;
  const productName = nameCol && row[nameCol] ? String(row[nameCol]).trim() : '';

  // Extract and parse image URLs (comma-separated)
  const imagesCol = detectedColumns.images;
  let imageUrls = [];
  if (imagesCol && row[imagesCol]) {
    const imageStr = String(row[imagesCol]).trim();
    imageUrls = imageStr.split(',').map(url => ({
      url: url.trim(),
      type: 'image'
    })).filter(img => img.url);
  }

  // Extract and parse video URLs (comma-separated)
  const videosCol = detectedColumns.videos;
  let videoUrls = [];
  if (videosCol && row[videosCol]) {
    const videoStr = String(row[videosCol]).trim();
    videoUrls = videoStr.split(',').map(url => ({
      url: url.trim(),
      type: 'video'
    })).filter(vid => vid.url);
  }

  // Extract description/marketing copy
  const descCol = detectedColumns.description;
  const marketingCopy = descCol && row[descCol] ? String(row[descCol]).trim() : '';

  // Extract price if available
  const priceCol = detectedColumns.price;
  const price = priceCol && row[priceCol] ? String(row[priceCol]).trim() : null;

  results.push({
    json: {
      sku: sku,
      product_name: productName,
      image_urls: imageUrls,
      video_urls: videoUrls,
      marketing_copy: marketingCopy,
      vendor_id: vendorId,
      source_tier: 1,
      metadata: {
        source: 'google_sheets',
        total_images: imageUrls.length,
        total_videos: videoUrls.length,
        price: price,
        detected_columns: detectedColumns
      },
      last_updated: new Date().toISOString()
    }
  });
}

return results;

// Handle multi-sheet structures
// Check if there are multiple sheets in the spreadsheet

const items = $input.all();
const results = [];

// Group by SKU in case there are duplicates across sheets
const productMap = {};

for (const item of items) {
  const sku = item.json.sku;

  if (!productMap[sku]) {
    productMap[sku] = item.json;
  } else {
    // Merge data if SKU already exists
    const existing = productMap[sku];

    // Merge image URLs
    existing.image_urls = [...existing.image_urls, ...item.json.image_urls];

    // Merge video URLs
    existing.video_urls = [...existing.video_urls, ...item.json.video_urls];

    // Use longer marketing copy
    if (item.json.marketing_copy.length > existing.marketing_copy.length) {
      existing.marketing_copy = item.json.marketing_copy;
    }

    // Update metadata
    existing.metadata.total_images = existing.image_urls.length;
    existing.metadata.total_videos = existing.video_urls.length;
  }
}

// Convert back to array
for (const sku in productMap) {
  results.push({ json: productMap[sku] });
}

return results;
